def _seed_default_loops(apps, schema_editor):
    """Idempotently seed the default loops + prompts in their final fresh-install shape.

    ``get_or_create`` by ``name`` so a re-run (or a fake-applied initial whose
    rows already exist) creates nothing new and never clobbers an operator-edited
    row. A prompt-backed loop's :class:`Prompt` is seeded first so the nullable FK
    resolves under the loop XOR constraint, and carries the loop's real
    description (matching ``teatree.loops.seed``). ``enabled`` is seeded from the
    per-loop ``default_enabled`` mark — on a fresh DB there is no operator
    ``LoopState`` hold, so seeding the sound-default set ON directly is identical
    to the old seed-paused-then-0043-flip.
    """
    Loop = apps.get_model("core", "Loop")
    Prompt = apps.get_model("core", "Prompt")
    # Scope every write to the alias the migration is running against (matches
    # 0004/0005) so a multi-DB / non-default-alias apply — e.g. a restored fleet
    # DB mounted under a different alias — seeds the DB being migrated, not the
    # default connection.
    db_alias = schema_editor.connection.alias
    for name, delay_seconds, daily_at, prompt_body, description, colleague_facing, default_enabled in _DEFAULT_LOOPS:
        prompt = None
        if prompt_body is not None:
            prompt, _ = Prompt.objects.using(db_alias).get_or_create(
                name=name,
                defaults={"body": prompt_body, "description": description},
            )
        defaults = {
            "delay_seconds": delay_seconds,
            "daily_at": daily_at,
            "description": description,
            "enabled": default_enabled,
            "colleague_facing": colleague_facing,
        }
        if prompt is not None:
            defaults["prompt"] = prompt
        else:
            defaults["script"] = f"src/teatree/loops/{name}/loop.py"
        Loop.objects.using(db_alias).get_or_create(name=name, defaults=defaults)


# --- ported verbatim from 0004_ticket_issue_number — _backfill_issue_number (Ticket) ---
# ``derive_issue_number`` is imported (rather than inlined as frozen history) on
# purpose: it is the stable pure trailing-digits helper ``Ticket.save`` also
# calls, so reusing it keeps the backfill and the live column-write byte-for-byte
# in agreement — an inlined copy could silently drift. It performs no DB access
# and reads no evolving schema, so the migration stays self-contained.


def _backfill_issue_number(apps, schema_editor):
    """Denormalize each existing ticket's forge issue number into the new column.

    Mirrors ``Ticket.save`` exactly (``derive_issue_number(issue_url)``) so the
    backfilled value equals what a subsequent save would write — the indexed
    ``_ticket_by_number`` lookup then agrees with the ``ticket_number`` property
    for every pre-existing row. Rows with a blank ``issue_url`` already hold the
    correct ``""`` default and are skipped.
    """
    ticket_model = apps.get_model("core", "Ticket")
    # Scope the read and the bulk_update to the alias the migration is running
    # against (matches 0005) so a multi-DB / non-default-alias apply backfills the
    # DB being migrated, not the default connection.
    db_alias = schema_editor.connection.alias
    pending = []
    for ticket in ticket_model.objects.using(db_alias).exclude(issue_url="").only("pk", "issue_url", "issue_number"):
        derived = derive_issue_number(ticket.issue_url)
        if ticket.issue_number != derived:
            ticket.issue_number = derived
            pending.append(ticket)
    ticket_model.objects.using(db_alias).bulk_update(pending, ["issue_number"], batch_size=500)


# --- ported verbatim from 0005_taskattempt_outcome — _backfill_outcome (TaskAttempt) ---
def _backfill_outcome(apps, schema_editor):
    """Stamp the new discriminator on existing rows from their exit_code + error (#16).

    Mirrors ``TaskAttempt._classify_outcome`` so a row recorded before this field
    existed reads the same first-class outcome the S5 signal now keys on: a clean
    ``exit_code == 0`` with no error is a success, ``exit_code == 0`` with an error
    is an envelope refusal, any non-zero exit is a crash, and a ``None`` exit_code
    (an attempt still in flight) stays blank.
    """
    TaskAttempt = apps.get_model("core", "TaskAttempt")
    db_alias = schema_editor.connection.alias
    rows = TaskAttempt.objects.using(db_alias)
    rows.filter(exit_code=0, error="").update(outcome="success")
    rows.filter(exit_code=0).exclude(error="").update(outcome="refusal")
    rows.filter(exit_code__isnull=False).exclude(exit_code=0).update(outcome="crash")


# --- ported verbatim from 0022_mode_booleans — _backfill_mode_booleans + _seed_offline_mode (LoopPreset); shared _noop_reverse below ---
# The recommended intrinsic posture per seeded mode (design §7-A, owner decision A):
# (defers_questions, pauses_self_pump, presence_sensitive). ``maintenance`` and
# ``low-power`` run at night / under token pressure — the owner is typically
# unreachable, so they defer; ``off`` is the reversible "calendar says nothing runs"
# (the owner may still be present) so it does not defer; ``offline`` is the NEW
# holiday-away mode that also pauses the pump (what no preset could express before).
_RECOMMENDED_POSTURE = {
    "engaged": (False, False, True),
    "heads-down": (False, False, True),
    "maintenance": (True, False, True),
    "unattended": (True, False, True),
    "low-power": (True, False, True),
    "off": (False, False, True),
    "offline": (True, True, False),
}

# The new holiday-away mode: every Loop-table loop off, defers + pauses the pump.
# It reproduces the old ``off`` preset + ``away`` availability combination that
# previously required setting BOTH handles — the two-handle friction the merge removes.
_OFFLINE_DESCRIPTION = "Holiday: every loop off, questions defer AND the self-pump pauses (was 'off' preset + 'away')."

# availability_mode string → (defers_questions, pauses_self_pump) for any row whose
# name is not in the recommended table (a custom operator preset). A blank pin means
# "no availability opinion" → present-class (F, F). Mirrors design §4.1.
_PIN_TO_BOOLEANS = {
    "autonomous_away": (True, False),
    "away": (True, True),
    "present": (False, False),
    "": (False, False),
}


def _backfill_mode_booleans(apps, schema_editor):
    """Back-fill the three intrinsic booleans on every existing LoopPreset (fail-open, idempotent)."""
    LoopPreset = apps.get_model("core", "LoopPreset")
    for preset in LoopPreset.objects.all():
        recommended = _RECOMMENDED_POSTURE.get(preset.name)
        if recommended is not None:
            defers, pauses, sensitive = recommended
        else:
            defers, pauses = _PIN_TO_BOOLEANS.get((preset.availability_mode or "").strip(), (False, False))
            sensitive = True
        preset.defers_questions = defers
        preset.pauses_self_pump = pauses
        preset.presence_sensitive = sensitive
        preset.save(update_fields=["defers_questions", "pauses_self_pump", "presence_sensitive"])


def _seed_offline_mode(apps, schema_editor):
    """Create the NEW ``offline`` holiday-away mode if absent (idempotent)."""
    LoopPreset = apps.get_model("core", "LoopPreset")
    Loop = apps.get_model("core", "Loop")
    if LoopPreset.objects.filter(name="offline").exists():
        return
    all_off = dict.fromkeys(Loop.objects.values_list("name", flat=True), False)
    LoopPreset.objects.create(
        name="offline",
        description=_OFFLINE_DESCRIPTION,
        entries=all_off,
        availability_mode="away",
        defers_questions=True,
        pauses_self_pump=True,
        presence_sensitive=False,
        overlay_scope=[],
    )


